mapper.select:
SELECT A.BUYER_NM, A.ANN_NO, A.BID_CNT, A.ANN_ITEM ,A.EV_TPL_SUBJECT, A.EV_TPL_NUM, A.EI_NUM ,A.BID_PROGRESS_CD, GETCOMCODE(A.GATE_CD, 'NH0024', A.BID_PROGRESS_CD, 0, #{ses.langCd}) AS BID_PROGRESS_LOC ,A.EU_PROGRESS_CD, A.EU_PROGRESS_LOC ,A.EU_USER_ID, A.EU_USER_NM ,A.JOIN_VENDOR_CNT, A.EVAL_VENDOR_CNT ,A.EU_REQ_DATE, A.BID_USER_ID, A.BID_USER_NM ,A.BUYER_CD, A.BID_NUM, A.VOTE_CNT FROM ( SELECT DISTINCT HD.BUYER_CD, getBuyerNames(HD.GATE_CD, HD.BUYER_CD, 'BID', HD.BID_NUM, HD.BID_CNT, null, #{ses.langCd}) AS BUYER_NM ,HD.ANN_NO, HD.BID_CNT, HD.ANN_ITEM ,TM.EV_TPL_SUBJECT, HD.EV_TPL_NUM, HD.EI_NUM
,(CASE WHEN (SELECT COUNT(S.VENDOR_CD) FROM STOCBDSP S WHERE S.GATE_CD = HD.GATE_CD AND S.BUYER_CD = HD.BUYER_CD AND S.BID_NUM = HD.BID_NUM AND S.BID_CNT = HD.BID_CNT AND S.DEL_FLAG = '0') = 0 THEN '200' ELSE '300' END) AS BID_PROGRESS_CD ,EU.PROGRESS_CD AS EU_PROGRESS_CD, GETCOMCODE(EU.GATE_CD, 'M122', EU.PROGRESS_CD, 0, #{ses.langCd}) AS EU_PROGRESS_LOC ,EU.EU_USER_ID, EU.EU_USER_NM AS EU_USER_NM ,GETBIDVENDORCNT(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'JOIN', '') AS JOIN_VENDOR_CNT ,GETBIDVENDORCNT(HD.GATE_CD, HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, 'EVAL', EU.EU_USER_ID) AS EVAL_VENDOR_CNT ,EU.EU_REQ_DATE ,HD.BID_USER_ID, GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd}) AS BID_USER_NM ,HD.GATE_CD, HD.BID_NUM, PG.VOTE_CNT FROM STOCBDHD HD JOIN STOCEVTM TM ON (TM.GATE_CD = HD.GATE_CD AND TM.BUYER_CD = HD.BUYER_CD AND TM.EV_TPL_NUM = HD.EV_TPL_NUM AND TM.DEL_FLAG = '0') JOIN STOCBDEU EU ON (EU.GATE_CD = HD.GATE_CD AND EU.BUYER_CD = HD.BUYER_CD AND EU.EI_NUM = HD.EI_NUM AND EU.PROGRESS_CD in ('200', '300') AND EU.DEL_FLAG = '0') JOIN STOCBDAP AP ON (AP.GATE_CD = HD.GATE_CD AND AP.BUYER_CD = HD.BUYER_CD AND AP.BID_NUM = HD.BID_NUM AND AP.BID_CNT = HD.BID_CNT AND AP.APP_DATE IS NOT NULL AND AP.FINAL_FLAG = '500' AND AP.DEL_FLAG = '0') LEFT OUTER JOIN STOCBDPG PG ON (HD.GATE_CD = PG.GATE_CD AND HD.BUYER_CD = PG.BUYER_CD AND HD.BID_NUM = PG.BID_NUM AND HD.BID_CNT = PG.BID_CNT) WHERE HD.GATE_CD = #{ses.gateCd} AND #{ses.companyCd} IN (SELECT UR.COMPANY_CD FROM STOCCVUR UR WHERE UR.GATE_CD = HD.GATE_CD AND UR.USER_ID IN (HD.BID_USER_ID, EU.EU_USER_ID)) AND HD.CONT_TYPE2 in ('TD', 'TS', 'NE') AND HD.SIGN_STATUS = 'E' AND HD.TECH_EV_TYPE = '20' AND (HD.BID_STATUS >= '2353' OR HD.BID_STATUS = '1300') AND HD.BID_STATUS != '9999' AND HD.DEL_FLAG = '0'
AND ((HD.CONT_TYPE2 IN ('TD') AND HD.APP_END_DATE HD.APP_END_TIME >= #{OPEN_DATE_FROM} '000000' AND HD.APP_END_DATE HD.APP_END_TIME <= #{OPEN_DATE_TO} '235959') OR (HD.CONT_TYPE2 IN ('TD', 'TS', 'NE') AND PG.OPEN_DATE PG.OPEN_TIME >= #{OPEN_DATE_FROM} '000000' AND PG.OPEN_DATE PG.OPEN_TIME <= #{OPEN_DATE_TO} '235959') )
AND UPPER(HD.EI_NUM) LIKE '%' UPPER(#{EI_NUM}) '%'
AND HD.BID_USER_ID = #{BID_USER_ID}
AND UPPER(GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd})) LIKE '%' UPPER(#{BID_USER_NM}) '%'
AND (UPPER(HD.ANN_NO) LIKE '%' UPPER(#{ANN_NO_ITEM}) '%' OR UPPER(REPLACE(HD.ANN_ITEM, ' ', '')) LIKE '%' UPPER(REPLACE(#{ANN_NO_ITEM}, ' ', '')) '%')
AND EU.EU_USER_ID = #{EU_USER_ID}
AND UPPER(EU.EU_USER_NM) LIKE '%' UPPER(#{EU_USER_NM}) '%'
AND HD.BUYER_CD = #{BUYER_CD}
) A WHERE 1 = 1
AND UPPER(A.BUYER_NM) LIKE '%' UPPER(#{BUYER_NM}) '%'
ORDER BY A.BID_NUM DESC

SELECT A.EU_USER_ID, A.EU_USER_NM ,A.EU_INSERT_FLAG, A.EU_FINISH_FLAG ,A.SUM_SCORE ,A.VENDOR_CD, A.VENDOR_NM ,A.ATT_FILE_NUM, A.REMARK ,A.BUYER_CD, A.BID_NUM, A.BID_CNT, A.EI_NUM, A.EU_SQ ,A.EV_EXCEPT_FLAG FROM ( SELECT EU.EU_USER_ID, EU.EU_USER_NM AS EU_USER_NM ,(CASE WHEN (SELECT COUNT(SUB_T.VENDOR_CD) FROM (SELECT T.VENDOR_CD FROM STOCBDET T WHERE T.GATE_CD = EU.GATE_CD AND T.BUYER_CD = EU.BUYER_CD AND T.EI_NUM = EU.EI_NUM AND T.EU_SQ = EU.EU_SQ AND T.VENDOR_CD = AP.VENDOR_CD AND T.DEL_FLAG = '0' GROUP BY T.GATE_CD, T.BUYER_CD, T.EI_NUM, T.EU_SQ, T.VENDOR_CD) SUB_T) > 0 THEN '1' ELSE '0' END) AS EU_INSERT_FLAG ,(CASE WHEN (SELECT COUNT(SUB_T.VENDOR_CD) FROM (SELECT T.VENDOR_CD FROM STOCBDET T WHERE T.GATE_CD = EU.GATE_CD AND T.BUYER_CD = EU.BUYER_CD AND T.EI_NUM = EU.EI_NUM AND T.EU_SQ = EU.EU_SQ AND T.VENDOR_CD = AP.VENDOR_CD AND (T.COMPLITE_FLAG, '-') = '1' AND T.DEL_FLAG = '0' GROUP BY T.GATE_CD, T.BUYER_CD, T.EI_NUM, T.EU_SQ, T.VENDOR_CD) SUB_T) > 0 THEN '1' ELSE '0' END) AS EU_FINISH_FLAG ,(SELECT SUM((T.RESULT_SCORE, 0)) FROM STOCBDET T WHERE T.GATE_CD = EU.GATE_CD AND T.BUYER_CD = EU.BUYER_CD AND T.EI_NUM = EU.EI_NUM AND T.EU_SQ = EU.EU_SQ AND T.VENDOR_CD = AP.VENDOR_CD AND T.DEL_FLAG = '0') AS SUM_SCORE ,(SELECT T.ATT_FILE_NUM FROM STOCBDET T WHERE T.GATE_CD = EU.GATE_CD AND T.BUYER_CD = EU.BUYER_CD AND T.EI_NUM = EU.EI_NUM AND T.EI_SQ = '0' AND T.EU_SQ = EU.EU_SQ AND T.VENDOR_CD = AP.VENDOR_CD AND T.DEL_FLAG = '0') AS ATT_FILE_NUM ,(SELECT T.REMARK FROM STOCBDET T WHERE T.GATE_CD = EU.GATE_CD AND T.BUYER_CD = EU.BUYER_CD AND T.EI_NUM = EU.EI_NUM AND T.EI_SQ = '0' AND T.EU_SQ = EU.EU_SQ AND T.VENDOR_CD = AP.VENDOR_CD AND T.DEL_FLAG = '0') AS REMARK ,AP.VENDOR_CD, GETVENDORNAME(AP.GATE_CD, AP.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM ,HD.BUYER_CD, HD.BID_NUM, HD.BID_CNT, HD.EI_NUM ,EU.EU_SQ ,(SELECT distinct T.EV_EXCEPT_FLAG FROM STOCBDET T WHERE T.GATE_CD = EU.GATE_CD AND T.BUYER_CD = EU.BUYER_CD AND T.EI_NUM = EU.EI_NUM AND T.EU_SQ = EU.EU_SQ AND T.VENDOR_CD = AP.VENDOR_CD AND T.DEL_FLAG = '0') AS EV_EXCEPT_FLAG FROM STOCBDHD HD JOIN STOCBDAP AP ON (AP.GATE_CD = HD.GATE_CD AND AP.BUYER_CD = HD.BUYER_CD AND AP.BID_NUM = HD.BID_NUM AND AP.BID_CNT = HD.BID_CNT AND AP.APP_DATE IS NOT NULL AND AP.FINAL_FLAG = '500' AND AP.DEL_FLAG = '0') LEFT JOIN STOCBDEU EU ON (EU.GATE_CD = HD.GATE_CD AND EU.BUYER_CD = HD.BUYER_CD AND EU.EI_NUM = HD.EI_NUM AND EU.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{BUYER_CD} AND HD.BID_NUM = #{BID_NUM} AND HD.BID_CNT = #{BID_CNT} AND HD.DEL_FLAG = '0' ) A WHERE 1 = 1
AND A.EU_INSERT_FLAG = #{EU_INSERT_FLAG}
AND UPPER(A.VENDOR_NM) LIKE '%' UPPER(#{VENDOR_NM}) '%'
AND A.EU_USER_ID = #{EU_USER_ID}
ORDER BY A.EU_USER_ID, A.VENDOR_CD

SELECT LISTAGG(EV.EI_SQ, ',') WITHIN GROUP(ORDER BY TO_NUMBER(EV.EI_SQ)) AS EI_SQ
  FROM STOCBDEV EV
 WHERE EV.GATE_CD = #{ses.gateCd}
   AND EV.BUYER_CD = #{BUYER_CD}
   AND EV.EI_NUM = #{EI_NUM}
   AND EV.DEL_FLAG = '0'

SELECT
     EV.EV_ITEM_TYPE_CD
    ,GETCOMCODE(EV.GATE_CD, (CASE EV.EV_ITEM_KIND_CD WHEN 'E' THEN 'M114' ELSE 'M113' END), EV.EV_ITEM_TYPE_CD, '0', #{ses.langCd}) AS EV_ITEM_TYPE_NM
  FROM STOCBDEV EV
 WHERE EV.GATE_CD = #{ses.gateCd}
   AND EV.BUYER_CD = #{BUYER_CD}
   AND EV.EI_NUM = #{EI_NUM}
   AND EV.DEL_FLAG = '0'
 GROUP BY EV.GATE_CD, EV.EV_ITEM_KIND_CD, EV.EV_ITEM_TYPE_CD
 ORDER BY TO_NUMBER(EV.EV_ITEM_TYPE_CD)

mapper.insert:
MERGE  STOCBDET BDET
USING (SELECT
             #{ses.gateCd} AS GATE_CD
            ,#{BUYER_CD} AS BUYER_CD
            ,#{EI_NUM} AS EI_NUM
            ,#{EI_SQ} AS EI_SQ
            ,#{EU_SQ} AS EU_SQ
            ,#{VENDOR_CD} AS VENDOR_CD
        ) B
 ON (BDET.GATE_CD = B.GATE_CD
 AND BDET.BUYER_CD = B.BUYER_CD
 AND BDET.EI_NUM = B.EI_NUM
 AND BDET.EI_SQ = B.EI_SQ
 AND BDET.EU_SQ = B.EU_SQ
 AND BDET.VENDOR_CD = B.VENDOR_CD)
WHEN MATCHED THEN
UPDATE SET
     MOD_DATE = SYSDATE
    ,MOD_USER_ID = #{ses.userId}
    ,SEL_EV_ID_SQ = #{SEL_EV_ID_SQ}
    ,RESULT_SCORE = #{RESULT_SCORE}
    ,ATT_FILE_NUM = #{ATT_FILE_NUM}
    ,REMARK = #{REMARK}
WHEN NOT MATCHED THEN
INSERT (
     GATE_CD
    ,BUYER_CD
    ,EI_NUM
    ,EI_SQ
    ,EU_SQ
    ,VENDOR_CD
    ,REG_DATE
    ,REG_USER_ID
    ,MOD_DATE
    ,MOD_USER_ID
    ,DEL_FLAG
    ,SEL_EV_ID_SQ
    ,RESULT_SCORE
    ,ATT_FILE_NUM
    ,REMARK
) VALUES (
     #{ses.gateCd}
    ,#{BUYER_CD}
    ,#{EI_NUM}
    ,#{EI_SQ}
    ,#{EU_SQ}
    ,#{VENDOR_CD}
    ,SYSDATE
    ,#{ses.userId}
    ,SYSDATE
    ,#{ses.userId}
    ,'0'
    ,#{SEL_EV_ID_SQ}
    ,#{RESULT_SCORE}
    ,#{ATT_FILE_NUM}
    ,#{REMARK}
)

mapper.select:
SELECT (CASE WHEN MAX(COMPLITE_FLAG) = '1' THEN 'Y' ELSE 'N' END) AS COMPLITE_FLAG FROM STOCBDET
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND EI_NUM = #{EI_NUM}
   AND EU_SQ = #{EU_SQ}
   AND VENDOR_CD = #{VENDOR_CD}
   AND DEL_FLAG = '0'

mapper.update:
UPDATE STOCBDET SET
     COMPLITE_DATE = SYSDATE
    ,COMPLITE_FLAG = '1'
 WHERE GATE_CD   = #{ses.gateCd}
   AND BUYER_CD  = #{BUYER_CD}
   AND EI_NUM    = #{EI_NUM}
   AND EU_SQ     = #{EU_SQ}
   AND VENDOR_CD = #{VENDOR_CD}
   AND DEL_FLAG  = '0'

mapper.select:
SELECT
    (CASE WHEN SUM(TOT.FINISH_VENDOR_CNT) = SUM(TOT.TOT_VENDOR_CNT) THEN 'Y' ELSE 'N' END) AS FINISH_POSSIBLE_FLAG
  FROM (
    SELECT
         COUNT(A.VENDOR_CD) AS FINISH_VENDOR_CNT
        ,0 AS TOT_VENDOR_CNT
      FROM (
        SELECT
            VENDOR_CD
          FROM STOCBDET
         WHERE GATE_CD  = #{ses.gateCd}
           AND BUYER_CD = #{BUYER_CD}
           AND EI_NUM   = #{EI_NUM}
           AND EU_SQ    = #{EU_SQ}
           AND (COMPLITE_FLAG, '0') = '1'
           AND DEL_FLAG = '0'
         GROUP BY GATE_CD, BUYER_CD, EI_NUM, EU_SQ, VENDOR_CD
      ) A

    UNION ALL

    SELECT
         0 AS FINISH_VENDOR_CNT
        ,COUNT(AP.VENDOR_CD) AS TOT_VENDOR_CNT
      FROM STOCBDAP AP
     WHERE AP.GATE_CD    = #{ses.gateCd}
       AND AP.BUYER_CD   = #{BUYER_CD}
       AND AP.BID_NUM    = #{BID_NUM}
       AND AP.BID_CNT    = #{BID_CNT}
       AND AP.APP_DATE IS NOT NULL
       AND AP.FINAL_FLAG = '500'
       AND AP.DEL_FLAG   = '0'
  ) TOT

mapper.update:
UPDATE STOCBDEU SET
     PROGRESS_CD = #{PROGRESS_CD}
    ,EU_EVAL_DATE = SYSDATE
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND EI_NUM = #{EI_NUM}
   AND EU_SQ = #{EU_SQ}

        UPDATE STOCBDET SET
			 MOD_DATE = SYSDATE
            ,EV_EXCEPT_FLAG = '1'
         WHERE GATE_CD   = #{ses.gateCd}
           AND BUYER_CD  = #{BUYER_CD}
           AND EI_NUM    = #{EI_NUM}
           AND EU_SQ     = #{EU_SQ}
           AND VENDOR_CD = #{VENDOR_CD}
           AND DEL_FLAG  = '0'

		UPDATE STOCBDHD SET
			 MOD_DATE    = SYSDATE
			,MOD_USER_ID = #{ses.userId}
            ,BID_STATUS  = #{BID_STATUS}
		 WHERE GATE_CD  = #{ses.gateCd}
		   AND BUYER_CD = #{BUYER_CD}
		   AND BID_NUM  = #{BID_NUM}
		   AND BID_CNT  = #{BID_CNT}

UPDATE STOCBDHD SET
	 MOD_DATE = SYSDATE
	,MOD_USER_ID = #{ses.userId}
	,EV_USER_ID = #{CHANGE_USER_ID}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND BID_NUM  = #{BID_NUM}
   AND BID_CNT  = #{BID_CNT}
